import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute, Router } from '@angular/router';
import { SeedService } from '../../data/seed.service';
import { Project, LineItem } from '../../data/models';

interface Milestone { label: string; date: string; done: boolean; }
interface ProjectDoc { name: string; type: string; date: string; }
interface Reminder { title: string; due: string; }

@Component({
  selector: 'app-project-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './project-detail.component.html',
  styleUrl: './project-detail.component.css',
})
export class ProjectDetailComponent {
  readonly id: string | null;
  readonly project: Project | undefined;

  readonly stageOrder: Project['stage'][] = ['quoting', 'submitted', 'negotiation', 'awarded', 'closed'];
  readonly tabs = ['scope', 'lineitems', 'quotes', 'pos', 'delivery', 'documents', 'reminders'];
  readonly activeTab = signal<string>('scope');

  // Illustrative inline data (mockup).
  readonly milestones: Milestone[] = [
    { label: 'Submittal package approved', date: '2026-06-20', done: true },
    { label: 'Release to manufacturing', date: '2026-07-15', done: true },
    { label: 'Factory acceptance test', date: '2026-08-28', done: false },
    { label: 'Ship to site', date: '2026-09-18', done: false },
    { label: 'On-site commissioning', date: '2026-10-05', done: false },
  ];

  readonly projectDocs: ProjectDoc[] = [
    { name: 'One-line diagram rev C', type: 'Drawing', date: '2026-06-12' },
    { name: 'Submittal package rev 3', type: 'Spec', date: '2026-06-28' },
    { name: 'Signed PO scan', type: 'PO', date: '2026-07-01' },
  ];

  readonly reminders: Reminder[] = [
    { title: 'Follow up on FAT scheduling window', due: '2026-08-01' },
    { title: 'Confirm site readiness with GC', due: '2026-09-01' },
  ];

  constructor(
    public seed: SeedService,
    private route: ActivatedRoute,
    private router: Router,
  ) {
    this.id = this.route.snapshot.paramMap.get('id');
    this.project = this.id ? this.seed.projectById(this.id) : undefined;

    const tab = this.route.snapshot.queryParamMap.get('tab');
    if (tab && this.tabs.includes(tab)) this.activeTab.set(tab);
  }

  selectTab(tab: string): void {
    this.activeTab.set(tab);
    this.router.navigate([], { queryParams: { tab }, queryParamsHandling: 'merge' });
  }

  projectQuotes() {
    return this.project ? this.seed.quotes().filter((q) => q.projectId === this.project!.id) : [];
  }

  // First word of the account name, used to loosely match illustrative orders.
  private accountFirstWord(): string {
    const name = this.project ? this.seed.accountById(this.project.accountId)?.name ?? '' : '';
    return name.split(/[\s—-]+/)[0]?.toLowerCase() ?? '';
  }

  projectOrders() {
    const word = this.accountFirstWord();
    if (!word) return [];
    return this.seed.orders().filter((o) => o.accountName.toLowerCase().includes(word));
  }

  lineItems(): LineItem[] {
    return this.seed.lineItems();
  }

  weightedNote = 'Margin is role-gated / internal.';

  lineBadge(status: LineItem['validationStatus']): string {
    switch (status) {
      case 'ok': return 'badge-success';
      case 'warning': return 'badge-warning';
      case 'error': return 'badge-danger';
      default: return 'badge-neutral';
    }
  }

  quoteBadge(status: string): string {
    switch (status) {
      case 'draft': return 'badge-neutral';
      case 'submitted': return 'badge-info';
      case 'won': return 'badge-success';
      case 'lost': return 'badge-danger';
      default: return 'badge-neutral';
    }
  }

  orderBadge(status: string): string {
    switch (status) {
      case 'confirmed': return 'badge-info';
      case 'in-production': return 'badge-warning';
      case 'shipped': return 'badge-success';
      case 'delivered': return 'badge-success';
      default: return 'badge-neutral';
    }
  }

  stageIndex(stage: Project['stage']): number {
    return this.stageOrder.indexOf(stage);
  }

  snooze(): void {
    // no-op mockup action
  }
}
